        $base + ['title' => 'Viking Wall Oven F7 Fault Code', 'slug' => 'viking-wall-oven-f7-fault-code',
            'meta_title' => 'Viking Wall Oven F7 Fault Code — Key Stuck on Control Panel',
            'meta_desc'  => 'The Viking wall oven F7 fault code means a keypad button is registering as permanently pressed. Learn causes, DIY drying steps, and when to call for repair.',
