                '_ar_causes'         => [['title' => 'NTC Thermistor Element Failure', 'description' => 'The negative temperature coefficient thermistor element has drifted out of specification or failed, sending incorrect temperature values to the control board.'], ['title' => 'Sensor Wiring Connector Corrosion', 'description' => 'Moisture and detergent in the dishwasher environment can corrode the sensor connector over time, breaking the signal circuit.']],
                '_ar_diy_steps'      => [['title' => 'Check for Error Code Display', 'description' => 'Viking dishwashers may display a specific error code for temperature sensor faults. Note the exact code and contact us — the code identifies the specific sensor circuit that has failed.'], ['title' => 'Verify Inlet Water Temperature', 'description' => 'Run the kitchen hot water tap until it reaches maximum temperature before starting the dishwasher. The inlet water should be at least 120°F. If inlet water is cold, the sensor may be correctly reporting that water is not reaching temperature.']],
                '_ar_when_to_call'   => 'Temperature sensor diagnosis requires testing the thermistor resistance at a known temperature reference point. Our technician replaces the failed sensor with a genuine Viking OEM component to restore correct wash cycle operation.',
