                '_ar_causes'         => [['title' => 'Sensor Lens Contamination', 'description' => 'Hard water mineral deposits, grease film, or detergent residue on the optical sensor lens cause false turbidity readings. Regular cleaning with a dishwasher cleaner tablet resolves this in many cases.'], ['title' => 'Sensor Optical Element Failure', 'description' => 'The LED emitter or photodetector in the turbidity sensor has failed, preventing the sensor from generating a valid turbidity signal.'], ['title' => 'Control Board Sensor Input Fault', 'description' => 'The control board sensor input circuit has developed a fault, unable to process the turbidity signal correctly.']],
                '_ar_diy_steps'      => [['title' => 'Run a Cleaning Cycle', 'description' => 'Place a dishwasher cleaning tablet (such as Affresh) in the bottom rack and run a hot wash cycle with the dishwasher empty. This dissolves mineral deposits that may be coating the turbidity sensor lens.'], ['title' => 'Clean the Filter Assembly', 'description' => 'A clogged filter can cause false soil readings. Remove, rinse, and reinstall the filter per the owner\'s manual cleaning procedure.']],
