                '_ar_causes'         => [['title' => 'Electrical Surge Damage', 'description' => 'A power surge through the household circuit has damaged microprocessor or relay components on the control board.'], ['title' => 'Moisture Ingress', 'description' => 'Condensation or a slow door seal leak has allowed moisture to reach the control board, corroding circuit traces or components over time.'], ['title' => 'Component Aging', 'description' => 'Electrolytic capacitors and relay contacts on the control board degrade with age, causing progressive PCB failure.']],
                '_ar_diy_steps'      => [['title' => 'Perform a Hard Reset', 'description' => 'Switch off the dishwasher circuit breaker for 5 minutes, then restore power. A control board in a fault state may clear with a full power reset. If errors or unresponsive behavior returns, the board requires professional diagnosis.']],
