        $base + ['title' => 'Viking Gas Cooktop Thermocouple Fault', 'slug' => 'viking-cooktop-thermocouple-fault',
            'meta_title' => 'Viking Gas Cooktop Thermocouple Failure — Burner Safety Shutdown',
            'meta_desc'  => 'Viking gas cooktop burner lighting but immediately extinguishing? A failed thermocouple is the most likely cause. Learn the diagnosis and professional repair.',
            'meta_fields' => ['_ar_brand' => 'Viking', '_ar_appliance_type' => 'Cooktop', '_ar_error_code' => 'Thermocouple Fault',
                '_ar_code_meaning'   => "Viking Professional gas cooktops use a thermocouple at each burner position as a flame safety device. The thermocouple is a bi-metal temperature sensor that generates a small millivolt signal when heated by the burner flame. This signal holds the gas safety valve open. When the thermocouple fails or degrades, it no longer generates sufficient voltage to hold the valve open, causing the burner flame to extinguish immediately after the ignition button is released — even with a fully lit burner.\n\nThermocouple failure is one of the most common Viking gas cooktop service issues. Each burner position has its own thermocouple, so failure typically affects only one burner at a time.",
                '_ar_causes'         => [['title' => 'Thermocouple Tip Degradation', 'description' => 'The metal tip of the thermocouple has oxidized or corroded from repeated flame exposure, reducing its thermoelectric output below the minimum required to hold the gas valve open.'], ['title' => 'Thermocouple Physical Damage', 'description' => 'Physical impact (from cleaning or cookware) has bent or cracked the thermocouple sheath, damaging the bi-metal element inside.'], ['title' => 'Dirty Thermocouple Contact Point', 'description' => 'Carbon deposits on the thermocouple tip from high-heat cooking or boilovers reduce the thermocouple\'s ability to generate sufficient millivoltage.']],
