        $base + ['title' => 'Viking Induction Cooktop Power Board Fault', 'slug' => 'viking-cooktop-induction-power-board-fault',
            'meta_title' => 'Viking Induction Cooktop Power Board Failure — Zone Not Heating',
            'meta_desc'  => 'Viking induction cooktop zone not heating despite pan detection? An induction power board fault may have occurred. Learn the diagnosis and repair.',
            'meta_fields' => ['_ar_brand' => 'Viking', '_ar_appliance_type' => 'Cooktop', '_ar_error_code' => 'Induction Power Board Fault',
                '_ar_code_meaning'   => "Viking induction cooktops use dedicated power board assemblies (also called inverter boards) that convert household line power into the high-frequency alternating current required to generate the induction magnetic field at each cooking zone. When a power board fault occurs — indicated by a zone that detects compatible cookware but fails to generate heat, often accompanied by an error code on the display — the power board for that zone requires professional replacement.\n\nViking induction power board faults can affect a single zone or multiple zones depending on the cooktop architecture. The control board handles user input and zone selection; the power board handles actual power delivery to the induction coil.",
                '_ar_causes'         => [['title' => 'IGBT Power Transistor Failure', 'description' => 'The insulated gate bipolar transistors (IGBTs) on the induction power board that switch the high-frequency current have failed, preventing the zone from generating an induction field.'], ['title' => 'Power Surge Damage', 'description' => 'A voltage spike has damaged power board components. Viking induction cooktops should be connected through a whole-home surge protector.'], ['title' => 'Overtemperature Shutdown', 'description' => 'Repeated thermal protection shutdowns from insufficient ventilation clearance or high ambient temperatures have stressed and eventually failed power board components.']],
                '_ar_diy_steps'      => [['title' => 'Confirm Cookware Compatibility', 'description' => 'Place a magnet on the bottom of the cookware. Strong magnet attraction (the magnet sticks without sliding) confirms compatible induction cookware. If the magnet does not stick firmly, the cookware is not compatible — this is not a power board fault.'], ['title' => 'Power Cycle the Cooktop', 'description' => 'Switch off the cooktop circuit breaker for 60 seconds and restore power. A temporary thermal protection shutdown may clear with a power reset.']],
