                '_ar_causes'         => [['title' => 'Thermistor Resistance Drift', 'description' => 'The NTC thermistor element has drifted outside specification, reporting an incorrect temperature that does not correspond to actual zone temperature.'], ['title' => 'Connector Corrosion in Humid Environment', 'description' => 'The wine storage environment — with frequent door openings and temperature differentials — can cause corrosion at thermistor connectors over time, creating intermittent or total signal loss.']],
                '_ar_diy_steps'      => [['title' => 'Compare Display Temperature to Actual Temperature', 'description' => 'Place a calibrated wine thermometer in the affected zone for 2 hours and compare the reading to the display. A significant discrepancy (more than 5°F) confirms the zone thermistor is not reading accurately.']],
