        $base + ['title' => 'Viking Vent Hood Thermal Cutout Tripped — Fan Shuts Off', 'slug' => 'viking-vent-hood-thermal-cutout-tripped',
            'meta_title' => 'Viking Vent Hood Shuts Off Unexpectedly — Thermal Overload',
