        $base + ['title' => 'Viking Vent Hood Low CFM — Ductwork Restriction Fault', 'slug' => 'viking-vent-hood-reduced-airflow-fault',
            'meta_title' => 'Viking Vent Hood Low Airflow — CFM Reduction and Duct Restriction',
            'meta_desc'  => 'Viking Professional range hood not moving enough air or smoke lingering over the cooktop? Ductwork restriction or a clogged grease filter may be causing low CFM.',
            'meta_fields' => ['_ar_brand' => 'Viking', '_ar_appliance_type' => 'Vent Hood', '_ar_error_code' => 'Low CFM / Airflow Restriction',
                '_ar_code_meaning'   => "Viking Professional Series range hoods are rated for specific cubic feet per minute (CFM) airflow performance. When actual airflow falls significantly below the rated CFM — evidenced by smoke or steam lingering at the cooktop rather than being captured by the hood — a restriction exists in the ventilation path. The airflow path includes the grease filters, blower housing, duct transition, duct run, and exterior wall cap.\n\nViking Professional hoods can move 600–1500+ CFM depending on the model. Even a partially clogged grease filter or a 90-degree duct bend too many can significantly reduce delivered airflow. Duct restriction is a performance issue rather than a component failure, but requires systematic diagnosis.",
                '_ar_causes'         => [['title' => 'Heavily Clogged Grease Filters', 'description' => 'Grease filters not cleaned in more than one month have accumulated sufficient grease to create significant airflow restriction. This is the most common and easily resolved cause of low CFM.'], ['title' => 'Restricted Duct Run', 'description' => 'The duct run has excess 90-degree elbows, uses flex duct with bends, or has accumulated grease deposits inside the duct — all of which reduce airflow velocity.'], ['title' => 'Exterior Wall Cap Partially Blocked', 'description' => 'The exterior wall termination cap has an obstruction (bird nest, debris, stuck damper blade) that restricts exhaust airflow at the termination point.'], ['title' => 'Duct Undersized for Blower CFM', 'description' => 'The installed duct is too small in diameter for the blower CFM rating of the Viking hood — a common installation error that causes permanent CFM restriction.']],
                '_ar_diy_steps'      => [['title' => 'Clean or Replace Grease Filters', 'description' => 'Remove the Viking grease filters and wash in hot water with degreasing detergent, or run through the dishwasher. Reinstall and test airflow. If significantly improved, the filters were the primary restriction.'], ['title' => 'Inspect Exterior Damper', 'description' => 'From outside the building, locate the vent hood wall or roof cap. Confirm the damper flaps open fully when the fan is running at high speed. A stuck or partially open damper significantly reduces exhaust airflow.']],
                '_ar_when_to_call'   => 'If filter cleaning does not restore adequate airflow, professional duct inspection — including measurement of static pressure and CFM delivery — is required to identify the restriction location. Our technicians carry duct performance measurement equipment for Viking hood systems.',
                '_ar_cost_range'     => '$0 – $380',
                '_ar_severity'       => 'Medium',
                '_ar_faqs'           => [['question' => 'How do I know if my Viking vent hood is moving enough air?', 'answer' => 'A properly functioning Viking Professional hood should capture all smoke and steam from the cooking surface without visible smoke escaping the capture zone. At high speed, you should feel noticeable air movement at the cooktop surface. If smoke or steam regularly escapes the hood capture zone during normal cooking, the delivered CFM is insufficient — either from restriction or an undersized ductwork installation.']]]],

        $base + ['title' => 'Viking Vent Hood Blower Motor Overtemperature Shutdown', 'slug' => 'viking-vent-hood-blower-overtemperature-fault',
            'meta_title' => 'Viking Vent Hood Fan Shutting Off — Blower Motor Overtemperature',
            'meta_desc'  => 'Viking Professional range hood fan shutting off unexpectedly during high-heat cooking? Blower motor overtemperature protection may have activated.',
            'meta_fields' => ['_ar_brand' => 'Viking', '_ar_appliance_type' => 'Vent Hood', '_ar_error_code' => 'Blower Motor Overtemperature / Thermal Cutout',
                '_ar_code_meaning'   => "Viking Professional Series blower motors include thermal overload protection that shuts the motor down if it exceeds safe operating temperatures — typically above 250°F at the motor housing. This protection prevents motor winding damage from sustained operation under high thermal load conditions. The fan will restart automatically after the motor cools, typically within 10–30 minutes.\n\nBlower motor overtemperature is distinct from the thermal cutout fault (a one-shot fusible thermal fuse). Overtemperature protection is a resetting device; the thermal cutout is non-resetting and requires component replacement when triggered. Repeated overtemperature events indicate a systemic issue that will eventually trigger the non-resetting thermal cutout.",
                '_ar_causes'         => [['title' => 'Severely Clogged Grease Filters', 'description' => 'Heavily loaded grease filters force the blower motor to work harder against the increased restriction, raising motor current and operating temperature.'], ['title' => 'Blower Wheel Grease Accumulation', 'description' => 'Grease buildup on the blower wheel impellers reduces fan efficiency, causing the motor to work harder to move the same volume of air.'], ['title' => 'Bearing Wear in Motor', 'description' => 'Worn motor bearings create additional friction that generates heat within the motor, eventually triggering overtemperature protection even at normal operating loads.'], ['title' => 'High Ambient Kitchen Temperature', 'description' => 'Extended high-heat cooking (wok cooking, sustained broiling) raises ambient kitchen air temperature, reducing the motor\'s ability to dissipate heat effectively.']],
                '_ar_diy_steps'      => [['title' => 'Clean Grease Filters Immediately', 'description' => 'Remove and thoroughly clean all grease filters in hot soapy water. Reinstall only when fully dry. Test hood at high speed after cleaning — improved continuous operation indicates filters were the primary cause of overtemperature.'], ['title' => 'Inspect Blower Wheel', 'description' => 'With the filters removed, shine a flashlight into the blower housing to inspect the impeller wheels for grease accumulation. Grease-loaded impellers require professional cleaning or replacement.']],
                '_ar_when_to_call'   => 'Repeated blower motor overtemperature events after filter cleaning require professional blower assembly inspection. A motor with worn bearings or a grease-loaded blower wheel that cannot be cleaned in place requires professional service and likely replacement.',
                '_ar_cost_range'     => '$0 – $420',
                '_ar_severity'       => 'Medium',
                '_ar_faqs'           => [['question' => 'My Viking hood fan stops working during high-heat cooking and restarts after 20 minutes — what is happening?', 'answer' => 'This is the blower motor thermal overload protection cycling. The motor overheats during sustained high-load operation and shuts down to prevent winding damage. It resets after cooling. This most commonly occurs when grease filters are heavily loaded or the blower wheel has accumulated significant grease. Clean the filters immediately and schedule a blower inspection. Repeated thermal overload events will eventually trigger the non-resetting thermal fuse, stopping the fan permanently.']]]],

