                '_ar_causes'         => [['title' => 'Power Surge Damage', 'description' => 'A voltage spike has damaged the microprocessor or motor driver components on the control PCB. Vent hoods connected to the same circuit as Viking ranges are particularly vulnerable to surges during range operation.'], ['title' => 'Moisture or Grease Vapor Damage', 'description' => 'Cooking vapors — particularly from high-heat wok or frying operations — that penetrate the control panel area can deposit a conductive grease film on PCB traces, causing short circuits or corrosion.'], ['title' => 'Component Aging', 'description' => 'Triac motor speed control components and relay contacts on the control board degrade with age, eventually failing to provide consistent speed control or switching.']],
                '_ar_diy_steps'      => [['title' => 'Power Cycle the Hood', 'description' => 'Switch off the vent hood circuit breaker for 60 seconds and restore power. A PCB in a fault state may clear with a full power reset. If controls remain unresponsive or erratic, the board requires professional diagnosis.'], ['title' => 'Clean the Control Panel Surface', 'description' => 'Grease film on touch control surfaces can mimic a control board fault. Clean the control panel surface with a stainless steel cleaner and a soft cloth, then retest all controls.']],
                '_ar_when_to_call'   => 'Control board replacement requires the correct Viking OEM board for the specific hood model and installation year. Our technician replaces the failed PCB and verifies all speed levels, lighting, and delay-off function before completing the repair.',
